import{_ as e,o as t,c as d,ag as o}from"./chunks/framework-C5-Jzrz4.js";const i=JSON.parse('{"title":"仓库内部工具与配置","description":"internal 目录下共享 lint、构建、TS、Tailwind 与 Node 工具的索引","frontmatter":{"title":"仓库内部工具与配置","description":"internal 目录下共享 lint、构建、TS、Tailwind 与 Node 工具的索引"},"headers":[],"relativePath":"scripts/guide/05-仓库内部工具与配置.md","filePath":"scripts/guide/05-仓库内部工具与配置.md","lastUpdated":null}');const c=e({name:"scripts/guide/05-仓库内部工具与配置.md"},[["render",function(e,i,c,n,a,l){return t(),d("div",null,[...i[0]||(i[0]=[o('<h1 id="仓库内部工具与配置" tabindex="-1">仓库内部工具与配置 <a class="header-anchor" href="#仓库内部工具与配置" aria-label="Permalink to &quot;仓库内部工具与配置&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>internal</code> 目录保存仓库级私有包和共享配置。它们不面向业务功能，而是为 monorepo 的 lint、构建、TypeScript 类型、样式和脚本流程提供基础能力。当前说明基于 <code>internal/README.md</code> 与各 package 源码整理，具体以源码导出为准。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>调整 lint 规则或提交规范</li><li>修改 Vite 构建与插件行为</li><li>统一 TypeScript / Tailwind / Node 工具的复用方式</li><li>理解 <code>apps/web-antd</code> 与 <code>packages</code> 对内部基础设施的依赖</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>internal/README.md</code></li><li><code>internal/lint-configs/*</code></li><li><code>internal/node-utils/src/*</code></li><li><code>internal/vite-config/src/*</code></li><li><code>internal/tsconfig/*.json</code></li><li><code>internal/tailwind-config/src/*</code></li></ul><h2 id="核心结构" tabindex="-1">核心结构 <a class="header-anchor" href="#核心结构" aria-label="Permalink to &quot;核心结构&quot;">​</a></h2><h3 id="lint-configs" tabindex="-1">lint-configs <a class="header-anchor" href="#lint-configs" aria-label="Permalink to &quot;lint-configs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>包名</th><th>目录</th><th>作用</th></tr></thead><tbody><tr><td><code>@vben/commitlint-config</code></td><td><code>internal/lint-configs/commitlint-config</code></td><td>提交信息规范与 scope 校验</td></tr><tr><td><code>@vben/eslint-config</code></td><td><code>internal/lint-configs/eslint-config</code></td><td>ESLint Flat Config 入口，组合 Vue、TypeScript、JSON、YAML、pnpm 等规则</td></tr><tr><td><code>@vben/oxlint-config</code></td><td><code>internal/lint-configs/oxlint-config</code></td><td>Oxlint 快速检查配置，作为 ESLint 的补充</td></tr><tr><td><code>@vben/oxfmt-config</code></td><td><code>internal/lint-configs/oxfmt-config</code></td><td>格式化配置封装</td></tr><tr><td><code>@vben/stylelint-config</code></td><td><code>internal/lint-configs/stylelint-config</code></td><td>CSS / SCSS 检查配置</td></tr></tbody></table><h3 id="node-utils" tabindex="-1">node-utils <a class="header-anchor" href="#node-utils" aria-label="Permalink to &quot;node-utils&quot;">​</a></h3><p><code>@vben/node-utils</code> 提供仓库内脚本与配置包共用的 Node 工具。常见模块包括：</p><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>src/monorepo.ts</code></td><td>查找仓库根目录、读取包清单</td></tr><tr><td><code>src/fs.ts</code></td><td>JSON 和文件读写</td></tr><tr><td><code>src/git.ts</code></td><td>staged 文件与 Git 相关操作</td></tr><tr><td><code>src/hash.ts</code></td><td>内容哈希生成</td></tr><tr><td><code>src/date.ts</code></td><td><code>dayjs</code> 相关能力</td></tr><tr><td><code>src/path.ts</code></td><td>路径格式化</td></tr><tr><td><code>src/formatter.ts</code></td><td>文件格式化入口</td></tr><tr><td><code>src/spinner.ts</code></td><td>CLI 加载态封装</td></tr></tbody></table><h3 id="vite-config" tabindex="-1">vite-config <a class="header-anchor" href="#vite-config" aria-label="Permalink to &quot;vite-config&quot;">​</a></h3><p><code>@vben/vite-config</code> 聚合了应用和库两类构建入口，核心导出包括 <code>defineConfig</code>、<code>defineApplicationConfig</code>、<code>defineLibraryConfig</code>、<code>loadApplicationPlugins</code> 和 <code>loadLibraryPlugins</code>。它内部组合了常见插件能力，例如国际化、打印信息、VXE Table 懒加载、启动页注入、压缩、PWA、HTML 处理、许可证检查、打包归档和构建可视化。</p><h3 id="tsconfig" tabindex="-1">tsconfig <a class="header-anchor" href="#tsconfig" aria-label="Permalink to &quot;tsconfig&quot;">​</a></h3><p><code>@vben/tsconfig</code> 通过 <code>internal/tsconfig/*.json</code> 提供共享模板，当前可见的配置有：</p><ul><li><code>base.json</code></li><li><code>node.json</code></li><li><code>library.json</code></li><li><code>web.json</code></li><li><code>web-app.json</code></li></ul><h3 id="tailwind-config" tabindex="-1">tailwind-config <a class="header-anchor" href="#tailwind-config" aria-label="Permalink to &quot;tailwind-config&quot;">​</a></h3><p><code>@vben/tailwind-config</code> 由 <code>src/index.ts</code> 和 <code>src/theme.css</code> 构成，作为 Tailwind 主题与公共样式变量的共享入口。</p><h2 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h2><ul><li><code>@vben/vite-config</code> 依赖 <code>@vben/node-utils</code></li><li><code>@vben/eslint-config</code> 与 <code>@vben/oxlint-config</code> 互为补充，避免重复检查</li><li><code>@vben/tsconfig</code> 被应用和库型 package 继承</li><li><code>@vben/tailwind-config</code> 通常被应用的构建入口直接引入</li></ul><h2 id="使用与扩展注意事项" tabindex="-1">使用与扩展注意事项 <a class="header-anchor" href="#使用与扩展注意事项" aria-label="Permalink to &quot;使用与扩展注意事项&quot;">​</a></h2><ul><li><code>internal</code> 下的 package 都是仓库私有能力，<code>package.json</code> 中均为 <code>private: true</code></li><li>修改导出时，先确认 <code>apps/web-antd</code>、<code>packages</code> 和脚本任务是否依赖现有 API</li><li>只调整源码和配置入口，不要把 <code>dist</code>、<code>node_modules</code> 等构建产物当作文档依据</li><li>需要更细粒度说明时，优先查看具体 package 的 <code>src/index.ts</code> 和相关实现文件</li></ul>',24)])])}]]);export{i as __pageData,c as default};
